import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.2UjvPF9X.js";const m=JSON.parse('{"title":"Lista de Verificación para Evitar Anti-patrones","description":"Lista de verificación para evitar anti-patrones en código RxJS: 16 mejores prácticas esenciales que cubren fugas de memoria, suscripciones, manejo de errores y selección de operadores","frontmatter":{"description":"Lista de verificación para evitar anti-patrones en código RxJS: 16 mejores prácticas esenciales que cubren fugas de memoria, suscripciones, manejo de errores y selección de operadores"},"headers":[],"relativePath":"es/guide/anti-patterns/checklist.md","filePath":"es/guide/anti-patterns/checklist.md","lastUpdated":1765383284000}'),i={name:"es/guide/anti-patterns/checklist.md"};function s(n,e,c,d,l,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="lista-de-verificacion-para-evitar-anti-patrones" tabindex="-1">Lista de Verificación para Evitar Anti-patrones <a class="header-anchor" href="#lista-de-verificacion-para-evitar-anti-patrones" aria-label="Permalink to &quot;Lista de Verificación para Evitar Anti-patrones&quot;">​</a></h1><p>Use esta lista de verificación para asegurarse de que su código RxJS no caiga en ningún anti-patrón. Haga clic en cada elemento para ver explicaciones detalladas y ejemplos de código.</p><h2 id="elementos-de-la-lista-de-verificacion" tabindex="-1">Elementos de la Lista de Verificación <a class="header-anchor" href="#elementos-de-la-lista-de-verificacion" aria-label="Permalink to &quot;Elementos de la Lista de Verificación&quot;">​</a></h2><h3 id="🔴-evitar-problemas-criticos" tabindex="-1">🔴 Evitar Problemas Críticos <a class="header-anchor" href="#🔴-evitar-problemas-criticos" aria-label="Permalink to &quot;🔴 Evitar Problemas Críticos&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Verificar</th><th>Elemento</th><th>Puntos Clave</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#1-publicacion-externa-de-subject">Publicar Subject con asObservable()</a></strong></td><td>No exportar <code>Subject</code> directamente, publicarlo como Observable con <code>asObservable()</code><br>Permitir cambios de estado solo a través de métodos dedicados</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#2-subscribe-anidado-callback-hell">Evitar subscribe anidado</a></strong></td><td>No llamar otro <code>subscribe</code> dentro de <code>subscribe</code><br>Aplanar con <code>switchMap</code>, <code>mergeMap</code>, <code>concatMap</code>, etc.</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#3-olvido-de-unsubscribe-fuga-de-memoria">Siempre desuscribirse de streams infinitos</a></strong></td><td>Siempre desuscribirse de streams infinitos como event listeners<br>Patrón <code>takeUntil</code> o gestión de <code>Subscription</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#4-mal-uso-de-sharereplay">Configurar explícitamente shareReplay</a></strong></td><td>Usar la forma <code>shareReplay({ bufferSize: 1, refCount: true })</code><br>Habilitar el conteo de referencias para prevenir fugas de memoria</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./subscribe-if-hell">Evitar sentencias if anidadas dentro de subscribe</a></strong></td><td>Evitar ramificación condicional compleja (3 o más niveles anidados) dentro de <code>subscribe</code><br>Escribir declarativamente con operadores como <code>filter</code>, <code>iif</code>, <code>partition</code></td></tr></tbody></table><h3 id="🟡-evitar-problemas-que-requieren-atencion" tabindex="-1">🟡 Evitar Problemas que Requieren Atención <a class="header-anchor" href="#🟡-evitar-problemas-que-requieren-atencion" aria-label="Permalink to &quot;🟡 Evitar Problemas que Requieren Atención&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Verificar</th><th>Elemento</th><th>Puntos Clave</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#5-efectos-secundarios-en-map">map es función pura, efectos secundarios en tap</a></strong></td><td>No cambiar el estado ni mostrar logs dentro de <code>map</code><br>Separar explícitamente los efectos secundarios con el operador <code>tap</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#6-ignorar-diferencias-entre-observable-cold-hot">Usar Cold/Hot apropiadamente</a></strong></td><td>Convertir solicitudes HTTP a Hot con <code>shareReplay</code><br>Determinar si la ejecución debe ocurrir por suscripción o ser compartida</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./promise-observable-mixing">Convertir Promise con from</a></strong></td><td>No mezclar Promise y Observable<br>Convertir a Observable con <code>from()</code> para procesamiento unificado</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#8-ignorar-backpressure">Controlar eventos de alta frecuencia</a></strong></td><td>Controlar entrada de búsqueda con <code>debounceTime</code>, desplazamiento con <code>throttleTime</code><br>Excluir duplicados con <code>distinctUntilChanged</code></td></tr></tbody></table><h3 id="🔵-mejorar-la-calidad-del-codigo" tabindex="-1">🔵 Mejorar la Calidad del Código <a class="header-anchor" href="#🔵-mejorar-la-calidad-del-codigo" aria-label="Permalink to &quot;🔵 Mejorar la Calidad del Código&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Verificar</th><th>Elemento</th><th>Puntos Clave</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#9-supresion-de-errores">Manejar errores apropiadamente</a></strong></td><td>Capturar errores con <code>catchError</code> y manejar apropiadamente<br>Mostrar mensajes de error amigables para el usuario<br>Reintentar con <code>retry</code> / <code>retryWhen</code> según sea necesario</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#10-fugas-de-suscripcion-de-eventos-dom">Liberar eventos DOM correctamente</a></strong></td><td>Siempre desuscribirse de suscripciones <code>fromEvent</code><br>Desuscribirse automáticamente con <code>takeUntil</code> cuando el componente se destruye</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#11-falta-de-seguridad-de-tipos-uso-excesivo-de-any">Asegurar la seguridad de tipos</a></strong></td><td>Definir interfaces y alias de tipos<br>Especificar explícitamente parámetros de tipo <code>Observable&lt;T&gt;</code><br>Aprovechar la inferencia de tipos de TypeScript</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#12-seleccion-impropia-de-operadores">Elegir operadores apropiados</a></strong></td><td>Búsqueda: <code>switchMap</code>, paralelo: <code>mergeMap</code><br>Secuencial: <code>concatMap</code>, prevenir doble clic: <code>exhaustMap</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#13-sobrecomplicacion">El procesamiento simple no necesita RxJS</a></strong></td><td>JavaScript regular es suficiente para procesamiento de arrays, etc.<br>Usar RxJS para procesamiento asíncrono y streams de eventos</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#14-cambios-de-estado-en-subscribe">Gestionar el estado reactivamente</a></strong></td><td>Gestionar el estado con <code>BehaviorSubject</code> o <code>scan</code><br>Usar <code>subscribe</code> como disparador final</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#15-falta-de-pruebas">Escribir pruebas</a></strong></td><td>Implementar marble testing con <code>TestScheduler</code><br>Hacer que el procesamiento asíncrono sea testeable de forma síncrona</td></tr></tbody></table><h2 id="como-usar" tabindex="-1">Cómo Usar <a class="header-anchor" href="#como-usar" aria-label="Permalink to &quot;Cómo Usar&quot;">​</a></h2><h3 id="_1-durante-la-revision-de-codigo" tabindex="-1">1. Durante la Revisión de Código <a class="header-anchor" href="#_1-durante-la-revision-de-codigo" aria-label="Permalink to &quot;1. Durante la Revisión de Código&quot;">​</a></h3><p>Después de escribir código nuevo, realice una auto-revisión usando esta lista de verificación.</p><h3 id="_2-durante-pull-requests" tabindex="-1">2. Durante Pull Requests <a class="header-anchor" href="#_2-durante-pull-requests" aria-label="Permalink to &quot;2. Durante Pull Requests&quot;">​</a></h3><p>Incluya esta lista de verificación en su plantilla de pull request para que los revisores puedan verificar con criterios comunes.</p><h3 id="_3-revisiones-regulares" tabindex="-1">3. Revisiones Regulares <a class="header-anchor" href="#_3-revisiones-regulares" aria-label="Permalink to &quot;3. Revisiones Regulares&quot;">​</a></h3><p>Use esta lista de verificación regularmente contra su base de código existente para verificar anti-patrones.</p><h3 id="_4-compartir-dentro-del-equipo" tabindex="-1">4. Compartir Dentro del Equipo <a class="header-anchor" href="#_4-compartir-dentro-del-equipo" aria-label="Permalink to &quot;4. Compartir Dentro del Equipo&quot;">​</a></h3><p>Comparta con los miembros del equipo para unificar las mejores prácticas de RxJS.</p><h2 id="recursos-relacionados" tabindex="-1">Recursos Relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos Relacionados&quot;">​</a></h2><ul><li><strong><a href="./common-mistakes">Errores Comunes y Cómo Corregirlos</a></strong> - Explicaciones detalladas y ejemplos de código para cada anti-patrón</li><li><strong><a href="./index">Inicio de Colección de Anti-Patrones</a></strong> - Lista de anti-patrones y cómo aprender</li><li><strong><a href="/RxJS-with-TypeScript/es/guide/error-handling/strategies">Manejo de Errores</a></strong> - Mejores prácticas de manejo de errores</li><li><strong><a href="/RxJS-with-TypeScript/es/guide/testing/unit-tests">Técnicas de Prueba</a></strong> - Cómo probar el código RxJS</li></ul><h2 id="consejos-para-usar-la-lista-de-verificacion" tabindex="-1">Consejos para Usar la Lista de Verificación <a class="header-anchor" href="#consejos-para-usar-la-lista-de-verificacion" aria-label="Permalink to &quot;Consejos para Usar la Lista de Verificación&quot;">​</a></h2><ol><li><p><strong>No intente perfeccionar todos los elementos a la vez</strong></p><ul><li>Primero, priorice los problemas críticos (🔴)</li><li>Mejore paso a paso</li></ul></li><li><p><strong>Establezca prioridades dentro del equipo</strong></p><ul><li>Ajuste la importancia según las características del proyecto</li><li>Cree listas de verificación personalizadas</li></ul></li><li><p><strong>Considere la automatización</strong></p><ul><li>Automatice verificaciones con herramientas de análisis estático como ESLint</li><li>Integre en el pipeline CI/CD</li></ul></li><li><p><strong>Actualizaciones regulares</strong></p><ul><li>Actualice según las actualizaciones de versión de RxJS</li><li>Refleje las ideas de la experiencia del equipo</li></ul></li></ol><hr><p><strong>Importante</strong>: Esta lista de verificación no es para escribir código perfecto, sino una guía para evitar problemas comunes. Úsela de forma flexible según el contexto de su proyecto.</p>',24)])])}const b=a(i,[["render",s]]);export{m as __pageData,b as default};
